16	import { state, escapeHtml } from "./utils.js";
17	
18	export async function triggerAnalysis(sessionId, force) {
19	  const btn = document.getElementById("summarize-btn");
20	  const aiContainer = document.getElementById("ai-summary-container");
21	  const aiText = document.getElementById("ai-summary-text");
22	
23	  if (force) {
24	    btn.disabled = true;
25	    btn.innerHTML = '<span class="sparkle-icon">⏳</span> Recomputing...';
26	  }
27	
28	  aiContainer.classList.remove("hidden");
29	
30	  if (force) {
31	    const content = document.getElementById("ai-summary-content");
32	    content.classList.remove("collapsed");
33	    const chevron = document
34	      .getElementById("ai-summary-header")
35	      .querySelector(".chevron");
36	    chevron.style.transform = "rotate(90deg)";
37	    aiText.innerHTML = "<em>Recomputing transcript analysis...</em>";
38	  } else if (!state.summaryCache[sessionId]) {
39	    aiText.innerHTML = "<em>Loading analysis...</em>";
40	  } else {
41	    aiText.innerHTML = state.summaryCache[sessionId];
42	    return; // already cached and not forced
43	  }
44	
45	  let currentPollSessionId = sessionId;
46	  state.currentPollSessionId = sessionId;
47	
48	  try {
49	    const flavor = encodeURIComponent(
50	      document.getElementById("flavor-select").value
51	    );
52	    let url = `/api/analysis/conversations/${sessionId}/summarize?flavor=${flavor}`;
53	    if (force) url += "&force=true";
54	
55	    // Progress UI
56	    if (force || !state.summaryCache[sessionId]) {
57	      const pContainer = document.createElement("div");
58	      pContainer.innerHTML = `
59	                <div style="font-size: 0.9rem; color: var(--text-secondary); margin-bottom: 8px;"><span id="progress-phase">Starting analysis...</span> <span id="progress-text">0%</span></div>
60	                <div style="width: 100%; height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; overflow: hidden;">
61	                    <div id="progress-bar" style="width: 0%; height: 100%; background: var(--accent-blue); transition: width 0.3s ease-out;"></div>
62	                </div>
63	            `;
64	      aiText.innerHTML = "";
65	      aiText.appendChild(pContainer);
66	    }
67	
68	    let polling = true;
69	    const pollProgress = async () => {
70	      while (polling && state.currentPollSessionId === sessionId) {
71	        try {
72	          const pres = await fetch(
73	            `/api/analysis/conversations/${sessionId}/progress`
74	          );
75	          if (pres.ok) {
76	            const pdata = await pres.json();
77	            if (
78	              pdata.progress >= 0 &&
79	              state.currentPollSessionId === sessionId
80	            ) {
81	              const phase = document.getElementById("progress-phase");
82	              const pt = document.getElementById("progress-text");
83	              const pb = document.getElementById("progress-bar");
84	              if (phase) phase.innerText = pdata.phase;
85	              if (pt) pt.innerText = pdata.progress + "%";
86	              if (pb) pb.style.width = pdata.progress + "%";
87	            }
88	          }
89	        } catch (e) {}
90	        await new Promise((r) => setTimeout(r, 1000));
91	      }
92	    };
93	
94	    pollProgress();
95	
96	    const res = await fetch(url);
97	    polling = false; // stop polling
98	
99	    const data = await res.json();
100	
101	    let html = "";
102	    if (data.summary) {
103	      html += `<p style="font-size: 1.05rem; margin-bottom: 24px; line-height: 1.6; color: var(--text-primary);">${escapeHtml(
104	        data.summary
105	      )}</p>`;
106	    }
107	
108	    if (data.flow && data.flow.length > 0) {
109	      html += `<h4 style="color: var(--accent-blue); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Conversation Flow</h4>`;
110	      html += `<ul style="list-style-type: none; padding-left: 0; margin-bottom: 24px;">`;
111	      data.flow.forEach((item, i) => {
112	        html += `<li style="margin-bottom: 10px; padding-left: 24px; position: relative; color: var(--text-secondary); line-height: 1.5;">
113	                    <span style="position: absolute; left: 0; top: 0; color: var(--accent-blue);">→</span>${escapeHtml(
114	                      item
115	                    )}
116	                </li>`;
117	      });
118	      html += `</ul>`;
119	    }
120	
121	    if (data.agentActions && data.agentActions.length > 0) {
122	      html += `<h4 style="color: var(--accent-purple); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Agent Actions Breakdown</h4>`;
123	      html += `<div style="display: flex; flex-direction: column; gap: 12px; margin-bottom: 24px;">`;
124	      data.agentActions.forEach((action) => {
125	        html += `<div style="background: rgba(30, 41, 59, 0.4); border: 1px solid rgba(255,255,255,0.05); border-radius: 6px; padding: 14px;">
126	                    <div style="font-weight: 600; color: var(--text-primary); margin-bottom: 6px; font-family: var(--font-mono); font-size: 0.85rem;">${escapeHtml(
127	                      action.action
128	                    )}</div>
129	                    <div style="font-size: 0.9rem; color: var(--text-secondary); line-height: 1.5;">${escapeHtml(
130	                      action.description
131	                    )}</div>
132	                </div>`;
133	      });
134	      html += `</div>`;
135	    }
136	
137	    if (data.issues && data.issues.length > 0) {
138	      html += `<h4 style="color: var(--error); margin-top: 16px; margin-bottom: 12px; font-size: 0.9rem; text-transform: uppercase; letter-spacing: 0.05em;">Issues & Circumventions</h4>`;
